400→										>
401→											<X className="h-3.5 w-3.5 mr-1" />
402→											Cancel
403→										</Button>
404→									</div>
405→								))}
406→						</div>
407→					</AnalyticsCard>
408→				)}
409→
410→				{/* Danger Zone */}
411→				<AnalyticsCard className="border-red-500/30">
412→					<h2 className="text-lg font-semibold text-red-500 mb-2">
413→						<AlertTriangle className="h-5 w-5 inline-block mr-2 -mt-0.5" />
414→						Danger Zone
415→					</h2>
416→					<p className="text-sm text-muted mb-4">
417→						Permanently delete this organization and all associated data.
418→					</p>
419→					{organizations.length <= 1 ? (
420→						<Button variant="destructive" size="sm" disabled>
421→							Cannot delete your only organization
422→						</Button>
