  1→import { AlertTriangle, Loader2 } from "lucide-react";
  2→import { useEffect, useState } from "react";
  3→import { client } from "../lib/orpc";
  4→import { Button } from "./ui/button";
  5→import {
  6→	Dialog,
  7→	DialogContent,
  8→	DialogDescription,
  9→	DialogFooter,
 10→	DialogHeader,
 11→	DialogTitle,
 12→} from "./ui/dialog";
 13→import { Input } from "./ui/input";
 14→
 15→interface DeleteOrganizationDialogProps {
 16→	open: boolean;
 17→	onOpenChange: (open: boolean) => void;
 18→	organization: { id: string; name: string };
 19→	otherOrganizations: { id: string; name: string }[];
 20→	onDeleted: () => void;
 21→}
 22→
 23→export function DeleteOrganizationDialog({
 24→	open,
 25→	onOpenChange,
 26→	organization,
 27→	otherOrganizations,
 28→	onDeleted,
 29→}: DeleteOrganizationDialogProps) {
 30→	const [sessionCount, setSessionCount] = useState<number | null>(null);
 31→	const [loading, setLoading] = useState(true);
 32→	const [sessionAction, setSessionAction] = useState<
 33→		"migrate" | "delete" | null
 34→	>(null);
 35→	const [migrateTarget, setMigrateTarget] = useState("");
 36→	const [confirmName, setConfirmName] = useState("");
 37→	const [deleting, setDeleting] = useState(false);
 38→	const [error, setError] = useState<string | null>(null);
 39→
 40→	useEffect(() => {
 41→		if (!open) {
 42→			setSessionCount(null);
 43→			setLoading(true);
 44→			setSessionAction(null);
 45→			setMigrateTarget("");
 46→			setConfirmName("");
 47→			setDeleting(false);
 48→			setError(null);
 49→			return;
 50→		}
 51→
 52→		client
 53→			.getOrganizationSessionCount({ organizationId: organization.id })
 54→			.then((res) => setSessionCount(res.count))
 55→			.catch(() => setSessionCount(0))
 56→			.finally(() => setLoading(false));
 57→	}, [open, organization.id]);
 58→
 59→	const nameMatches =
 60→		confirmName.toLowerCase() === organization.name.toLowerCase();
 61→	const canDelete =
 62→		nameMatches &&
 63→		!deleting &&
 64→		(sessionCount === 0 ||
 65→			sessionAction === "delete" ||
 66→			(sessionAction === "migrate" && migrateTarget));
 67→
 68→	const handleDelete = async () => {
 69→		setDeleting(true);
 70→		setError(null);
 71→		try {
 72→			await client.deleteOrganization({
 73→				organizationId: organization.id,
 74→				migrateSessionsTo:
 75→					sessionAction === "migrate" ? migrateTarget : undefined,
 76→			});
 77→			onDeleted();
 78→		} catch (err) {
 79→			setError(
 80→				err instanceof Error ? err.message : "Failed to delete organization",
 81→			);
 82→			setDeleting(false);
 83→		}
 84→	};
 85→
 86→	return (
 87→		<Dialog open={open} onOpenChange={onOpenChange}>
 88→			<DialogContent>
 89→				<DialogHeader>
 90→					<DialogTitle className="flex items-center gap-2">
 91→						<AlertTriangle className="h-5 w-5 text-red-500" />
 92→						Delete Organization
 93→					</DialogTitle>
 94→					<DialogDescription>
 95→						This action cannot be undone. This will permanently delete{" "}
 96→						<strong>{organization.name}</strong> and remove all member access.
 97→					</DialogDescription>
 98→				</DialogHeader>
 99→
100→				{loading ? (
101→					<div className="flex items-center justify-center py-8">
102→						<Loader2 className="h-6 w-6 animate-spin text-muted" />
103→					</div>
104→				) : (
105→					<div className="flex flex-col gap-4">
106→						{sessionCount !== null && sessionCount > 0 ? (
107→							<>
108→								<p className="text-sm text-foreground">
109→									This organization has{" "}
110→									<strong>
111→										{sessionCount} session{sessionCount !== 1 ? "s" : ""}
112→									</strong>
113→									.
114→								</p>
115→
116→								<div className="flex flex-col gap-2">
117→									<label className="flex items-start gap-2 rounded-lg border border-border p-3 cursor-pointer has-[:checked]:border-foreground">
118→										<input
119→											type="radio"
120→											name="sessionAction"
121→											value="migrate"
122→											checked={sessionAction === "migrate"}
123→											onChange={() => setSessionAction("migrate")}
124→											className="mt-0.5"
125→										/>
126→										<div className="flex flex-col gap-1">
127→											<span className="text-sm font-medium text-foreground">
128→												Migrate sessions
129→											</span>
130→											<span className="text-xs text-muted">
131→												Move all sessions to another organization
132→											</span>
133→											{sessionAction === "migrate" && (
134→												<select
