import { useQuery } from "@tanstack/react-query";
import {
	Activity,
	Bot,
	FolderKanban,
	Sparkles,
	Terminal,
	Users,
} from "lucide-react";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { CliSetupHint } from "@/components/analytics/CliSetupHint";
import { DatePicker } from "@/components/analytics/DatePicker";
import { InsightCard } from "@/components/analytics/InsightCard";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { ModelTokensChart } from "@/components/charts/ModelTokensChart";
import { UsageTrendChart } from "@/components/charts/UsageTrendChart";
import { Spinner } from "@/components/ui/spinner";
import { useDateRange } from "@/contexts/DateRangeContext";
import { orpc } from "@/lib/orpc";

export function OverviewPage() {
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const { data: kpis, isLoading: kpisLoading } = useQuery(
		orpc.analytics.overview.kpis.queryOptions({ input: { days } }),
	);

	const { data: usageTrendData } = useQuery(
		orpc.analytics.overview.usageTrend.queryOptions({ input: { days } }),
	);

	const { data: modelTokensData } = useQuery(
		orpc.analytics.overview.modelTokensTrend.queryOptions({
			input: { days },
		}),
	);

	const { data: insights } = useQuery(
		orpc.analytics.overview.insights.queryOptions({ input: { days } }),
	);

	const hasData = !kpisLoading && kpis && kpis.distinct_sessions > 0;

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Dashboard Overview"
				description="Track your team's Claude Code usage and metrics"
				actions={
					hasData ? (
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					) : undefined
				}
			/>

			{kpisLoading && (
				<div className="flex items-center justify-center py-12">
					<div className="text-center">
						<Spinner size="lg" className="mb-4" />
						<p className="text-muted">Loading dashboard data...</p>
					</div>
				</div>
			)}

			{!kpisLoading && kpis && kpis.distinct_sessions === 0 && <CliSetupHint />}

			{hasData && (
				<>
					<div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 mb-8">
						<StatCard
							title="Distinct Users"
							value={kpis.distinct_users.toLocaleString()}
							icon={Users}
							iconColor="text-green-600"
							href="/dashboard/developers"
							linkLabel="Go to users"
						/>
						<StatCard
							title="Distinct Sessions"
							value={kpis.distinct_sessions.toLocaleString()}
							icon={Activity}
							iconColor="text-blue-600"
							href="/dashboard/sessions"
							linkLabel="Go to sessions"
						/>
						<StatCard
							title="Distinct Projects"
							value={kpis.distinct_projects.toLocaleString()}
							icon={FolderKanban}
							iconColor="text-purple-600"
							href="/dashboard/projects"
							linkLabel="Go to projects"
						/>
						<StatCard
							title="Distinct Subagents"
							value={kpis.distinct_subagents.toLocaleString()}
							icon={Bot}
							iconColor="text-orange-600"
							href="/dashboard/sessions"
							linkLabel="Go to sessions"
						/>
						<StatCard
							title="Slash Commands"
							value={kpis.distinct_slash_commands.toLocaleString()}
							icon={Terminal}
							iconColor="text-cyan-600"
							href="/dashboard/sessions"
							linkLabel="Go to sessions"
						/>
						<StatCard
							title="Distinct Skills"
							value={kpis.distinct_skills.toLocaleString()}
							icon={Sparkles}
							iconColor="text-pink-600"
							href="/dashboard/sessions"
							linkLabel="Go to sessions"
						/>
					</div>

					{insights && insights.length > 0 && (
						<div className="mb-8">
							<h2 className="text-xl font-bold text-heading mb-4">
								Quick Insights
							</h2>
							<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
								{insights.map((insight, index) => (
									<InsightCard
										// biome-ignore lint/suspicious/noArrayIndexKey: static insights list
										key={index}
										insight={{
											type: insight.type as
												| "trend"
												| "performer"
												| "alert"
												| "info",
											severity: insight.severity,
											message: insight.message,
											link: insight.link || "/dashboard",
										}}
									/>
								))}
							</div>
						</div>
					)}

					{usageTrendData && usageTrendData.length > 0 && (
						<AnalyticsCard className="mb-8">
							<h2 className="text-xl font-bold text-heading mb-4">
								Usage Trends
							</h2>
							<p className="text-sm text-muted mb-6">
								Track key metrics over time - switch between metric pairs to see
								different views
							</p>
							<UsageTrendChart
								data={usageTrendData}
								showRollingAverage={false}
							/>
						</AnalyticsCard>
					)}

					{modelTokensData && modelTokensData.length > 0 && (
						<AnalyticsCard className="mb-8">
							<h2 className="text-xl font-bold text-heading mb-4">
								Tokens by Model
							</h2>
							<p className="text-sm text-muted mb-6">
								Token consumption broken down by model type over time
							</p>
							<ModelTokensChart data={modelTokensData} />
						</AnalyticsCard>
					)}
				</>
			)}
		</div>
	);
}

import type { DeveloperSummary } from "@rudel/api-routes";
import { useQuery } from "@tanstack/react-query";
import type { ColumnDef } from "@tanstack/react-table";
import {
	Activity,
	ArrowDown,
	ArrowUp,
	Clock,
	Code,
	Minus,
	UserCheck,
	Users,
} from "lucide-react";
import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { DeveloperTrendChart } from "@/components/charts/DeveloperTrendChart";
import { DataTable } from "@/components/ui/data-table";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useOrganization } from "@/contexts/OrganizationContext";
import { authClient } from "@/lib/auth-client";
import { formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

export function DevelopersListPage() {
	const navigate = useNavigate();
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const { activeOrg } = useOrganization();
	const [memberCount, setMemberCount] = useState<number | null>(null);

	// biome-ignore lint/correctness/useExhaustiveDependencies: refetch when org changes
	useEffect(() => {
		if (!activeOrg) return;
		authClient.organization
			.getFullOrganization({ query: { organizationId: activeOrg.id } })
			.then((res) => {
				if (res.data) {
					setMemberCount(
						(res.data as { members: readonly unknown[] }).members.length,
					);
				}
			});
	}, [activeOrg?.id]);

	const { data: developers, isLoading } = useQuery(
		orpc.analytics.developers.list.queryOptions({ input: { days } }),
	);

	const { data: trendsData } = useQuery(
		orpc.analytics.developers.trends.queryOptions({ input: { days } }),
	);

	const { data: userMappings } = useQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
	);

	const userMap = useMemo(() => {
		const map = new Map<string, string>();
		if (userMappings) {
			for (const m of userMappings) {
				map.set(m.user_id, m.username);
			}
		}
		return map;
	}, [userMappings]);

	const userMapRecord = useMemo(() => Object.fromEntries(userMap), [userMap]);

	const columns = useMemo<ColumnDef<DeveloperSummary>[]>(
		() => [
			{
				accessorFn: (row) => formatUsername(row.user_id, userMapRecord),
				id: "developer",
				header: "Developer",
				cell: ({ row }) => (
					<div className="flex items-center">
						<div className="flex-shrink-0 h-10 w-10 bg-blue-100 rounded-full flex items-center justify-center">
							<span className="text-blue-600 font-semibold text-sm">
								{formatUsername(row.original.user_id, userMapRecord)
									.substring(0, 2)
									.toUpperCase()}
							</span>
						</div>
						<div className="ml-4">
							<div className="text-sm font-medium text-foreground">
								{formatUsername(row.original.user_id, userMapRecord)}
							</div>
						</div>
					</div>
				),
			},
			{
				accessorKey: "total_sessions",
				header: "Sessions",
				cell: ({ row }) => (
					<span className="text-muted">{row.original.total_sessions}</span>
				),
			},
			{
				accessorKey: "active_days",
				header: "Active Days",
				cell: ({ row }) => (
					<span className="text-muted">{row.original.active_days}</span>
				),
			},
			{
				accessorKey: "total_tokens",
				header: "Total Tokens",
				cell: ({ row }) => (
					<span className="text-muted">
						{(row.original.total_tokens / 1000).toFixed(0)}K
					</span>
				),
			},
			{
				accessorKey: "success_rate",
				header: "Success Rate",
				cell: ({ row }) => {
					const rate = row.original.success_rate;
					const color =
						rate >= 70
							? "text-status-success-icon"
							: rate >= 50
								? "text-status-warning-icon"
								: "text-status-error-icon";
					return (
						<span className={`font-medium ${color}`}>{rate.toFixed(0)}%</span>
					);
				},
			},
			{
				accessorKey: "cost",
				header: "Cost",
				cell: ({ row }) => (
					<span className="text-muted">${row.original.cost.toFixed(2)}</span>
				),
			},
			{
				accessorKey: "success_rate_trend",
				header: "Trend",
				cell: ({ row }) => {
					const trend = row.original.success_rate_trend;
					return (
						<div className="flex items-center">
							{trend > 0 && (
								<>
									<ArrowUp className="w-4 h-4 text-status-success-icon mr-1" />
									<span className="text-status-success-icon font-medium">
										+{trend.toFixed(0)}%
									</span>
								</>
							)}
							{trend < 0 && (
								<>
									<ArrowDown className="w-4 h-4 text-status-error-icon mr-1" />
									<span className="text-status-error-icon font-medium">
										{trend.toFixed(0)}%
									</span>
								</>
							)}
							{trend === 0 && (
								<>
									<Minus className="w-4 h-4 text-muted mr-1" />
									<span className="text-muted">0%</span>
								</>
							)}
						</div>
					);
				},
			},
			{
				accessorKey: "avg_session_duration_min",
				header: "Avg Session",
				cell: ({ row }) => (
					<span className="text-muted">
						{row.original.avg_session_duration_min.toFixed(0)}m
					</span>
				),
			},
			{
				accessorFn: (row) => new Date(row.last_active_date).getTime(),
				id: "last_active",
				header: "Last Active",
				cell: ({ row }) => (
					<span className="text-muted">
						{new Date(row.original.last_active_date).toLocaleDateString()}
					</span>
				),
			},
		],
		[userMapRecord],
	);

	const totalSessions =
		developers?.reduce((sum, d) => sum + d.total_sessions, 0) ?? 0;
	const totalTokens =
		developers?.reduce((sum, d) => sum + d.total_tokens, 0) ?? 0;
	const totalHours =
		(developers?.reduce((sum, d) => sum + d.total_duration_min, 0) ?? 0) / 60;

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Developers"
					description="Individual developer activity and metrics"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading developers...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Developers"
				description="Individual developer activity and metrics"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{/* Summary Stats */}
			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-6 mb-8">
				<StatCard
					title="Team Members"
					value={memberCount ?? "..."}
					icon={Users}
					iconColor="text-blue-600"
				/>
				<StatCard
					title="Active Developers"
					value={developers?.length ?? 0}
					icon={UserCheck}
					iconColor="text-cyan-600"
				/>
				<StatCard
					title="Total Sessions"
					value={totalSessions.toLocaleString()}
					icon={Activity}
					iconColor="text-green-600"
				/>
				<StatCard
					title="Total Tokens"
					value={`${(totalTokens / 1000000).toFixed(1)}M`}
					icon={Code}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Total Hours"
					value={totalHours.toFixed(0)}
					icon={Clock}
					iconColor="text-orange-600"
				/>
			</div>

			{/* Developers Table */}
			<AnalyticsCard>
				<h2 className="text-xl font-bold text-heading mb-4">Developer List</h2>
				<DataTable
					columns={columns}
					data={developers ?? []}
					defaultSorting={[{ id: "total_sessions", desc: true }]}
					onRowClick={(row) => navigate(`/dashboard/developers/${row.user_id}`)}
				/>
			</AnalyticsCard>

			{/* Developer Trend Chart */}
			{trendsData && trendsData.length > 0 && (
				<AnalyticsCard className="mt-8">
					<h2 className="text-xl font-bold text-heading mb-4">
						Developer Activity Trends
					</h2>
					<p className="text-sm text-muted mb-6">
						Activity metrics over time split by developer
					</p>
					<DeveloperTrendChart data={trendsData} userMap={userMap} />
				</AnalyticsCard>
			)}
		</div>
	);
}

