import type {
	DimensionAnalysisInput,
	SessionAnalytics,
} from "@rudel/api-routes";
import { useQuery } from "@tanstack/react-query";
import type { ColumnDef } from "@tanstack/react-table";
import { Activity, Clock, Timer } from "lucide-react";
import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { MultiSelect } from "@/components/analytics/MultiSelect";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { DimensionAnalysisChart } from "@/components/charts/DimensionAnalysisChart";
import { DataTable } from "@/components/ui/data-table";
import {
	Select,
	SelectContent,
	SelectItem,
	SelectTrigger,
	SelectValue,
} from "@/components/ui/select";
import { Spinner } from "@/components/ui/spinner";
import { Switch } from "@/components/ui/switch";
import { useDateRange } from "@/contexts/DateRangeContext";
import { calculateCost, formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

export function SessionsListPage() {
	const navigate = useNavigate();
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const [selectedRepositories, setSelectedRepositories] = useState<string[]>(
		[],
	);
	const [selectedUsers, setSelectedUsers] = useState<string[]>([]);

	const [selectedDimension, setSelectedDimension] =
		useState<DimensionAnalysisInput["dimension"]>("repository");
	const [selectedMetric, setSelectedMetric] =
		useState<DimensionAnalysisInput["metric"]>("session_count");
	const [selectedSplitBy, setSelectedSplitBy] = useState<
		DimensionAnalysisInput["dimension"] | ""
	>("");
	const [showPercentage, setShowPercentage] = useState(false);

	const [debouncedDimension, setDebouncedDimension] =
		useState<DimensionAnalysisInput["dimension"]>("repository");
	const [debouncedMetric, setDebouncedMetric] =
		useState<DimensionAnalysisInput["metric"]>("session_count");
	const [debouncedSplitBy, setDebouncedSplitBy] = useState<
		DimensionAnalysisInput["dimension"] | ""
	>("");

	useEffect(() => {
		const timer = setTimeout(() => {
			setDebouncedDimension(selectedDimension);
			setDebouncedMetric(selectedMetric);
			setDebouncedSplitBy(selectedSplitBy);
		}, 300);
		return () => clearTimeout(timer);
	}, [selectedDimension, selectedMetric, selectedSplitBy]);

	const { data: summary } = useQuery(
		orpc.analytics.sessions.summary.queryOptions({ input: { days } }),
	);

	const { data: comparison } = useQuery(
		orpc.analytics.sessions.summaryComparison.queryOptions({
			input: { days },
		}),
	);

	const { data: sessions, isLoading } = useQuery(
		orpc.analytics.sessions.list.queryOptions({
			input: { days, limit: 100, sortBy: "session_date", sortOrder: "desc" },
		}),
	);

	const { data: userMappings } = useQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
	);

	const { data: dimensionData, isLoading: dimensionLoading } = useQuery(
		orpc.analytics.sessions.dimensionAnalysis.queryOptions({
			input: {
				days,
				dimension: debouncedDimension,
				metric: debouncedMetric,
				splitBy: debouncedSplitBy || undefined,
				limit: 10,
			},
		}),
	);

	const userMap = useMemo(() => {
		const map = new Map<string, string>();
		if (userMappings) {
			for (const m of userMappings) {
				map.set(m.user_id, m.username);
			}
		}
		return map;
	}, [userMappings]);

	const userMapRecord = useMemo(() => Object.fromEntries(userMap), [userMap]);

	const columns = useMemo<ColumnDef<SessionAnalytics>[]>(
		() => [
			{
				accessorKey: "session_id",
				header: "Session ID",
				cell: ({ row }) => (
					<span className="text-accent font-mono text-xs">
						{row.original.session_id.slice(0, 8)}...
					</span>
				),
			},
			{
				accessorFn: (row) => new Date(row.session_date).getTime(),
				id: "date",
				header: "Date",
				cell: ({ row }) => (
					<div>
						<span className="text-foreground">
							{new Date(row.original.session_date).toLocaleDateString()}
						</span>
						<br />
						<span className="text-xs text-muted">
							{new Date(row.original.session_date).toLocaleTimeString()}
						</span>
					</div>
				),
			},
			{
				accessorFn: (row) => formatUsername(row.user_id, userMapRecord),
				id: "user",
				header: "User",
				cell: ({ row }) => (
					<span className="text-subheading">
						{formatUsername(row.original.user_id, userMapRecord)}
					</span>
				),
			},
			{
				accessorKey: "project_path",
				header: "Project",
				cell: ({ row }) => (
					<div
						className="max-w-xs truncate"
						title={row.original.git_remote || row.original.project_path}
					>
						{row.original.git_remote
							? row.original.git_remote.split("/").pop()
							: row.original.project_path.split("/").pop() ||
								row.original.project_path}
					</div>
				),
			},
			{
				accessorKey: "duration_min",
				header: "Duration",
				cell: ({ row }) => (
					<span className="text-foreground">
						{row.original.duration_min.toFixed(0)} min
					</span>
				),
			},
			{
				accessorKey: "success_score",
				header: "Success Score",
				cell: ({ row }) => {
					const score = row.original.success_score;
					const color =
						score >= 70
							? "text-status-success-icon"
							: score >= 40
								? "text-status-warning-icon"
								: "text-status-error-icon";
					return (
						<>
							<span className={`font-semibold ${color}`}>
								{score.toFixed(0)}
							</span>
							<span className="text-xs text-muted"> / 100</span>
						</>
					);
				},
			},
			{
				accessorFn: (row) => calculateCost(row.input_tokens, row.output_tokens),
				id: "cost",
				header: "Cost",
				cell: ({ row }) => (
					<span className="text-foreground font-mono">
						$
						{calculateCost(
							row.original.input_tokens,
							row.original.output_tokens,
						).toFixed(4)}
					</span>
				),
			},
		],
		[userMapRecord],
	);

	const filteredSessions = useMemo(() => {
		if (!sessions) return [];
		return sessions.filter((session) => {
			const repoMatch =
				selectedRepositories.length === 0 ||
				(session.repository &&
					selectedRepositories.includes(session.repository));
			const userMatch =
				selectedUsers.length === 0 || selectedUsers.includes(session.user_id);
			return repoMatch && userMatch;
		});
	}, [sessions, selectedRepositories, selectedUsers]);

	const repositories = useMemo(() => {
		if (!sessions) return [];
		return Array.from(
			new Set(sessions.map((s) => s.repository).filter(Boolean)),
		).sort() as string[];
	}, [sessions]);

	const users = useMemo(() => {
		if (!sessions) return [];
		return Array.from(
			new Set(sessions.map((s) => s.user_id).filter(Boolean)),
		).sort();
	}, [sessions]);

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Sessions"
					description="Analyze session interaction timing and patterns"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading session analytics...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Sessions"
				description="Analyze session interaction timing and patterns"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{summary && comparison && (
				<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
					<StatCard
						title="Total Sessions"
						value={summary.total_sessions.toLocaleString()}
						icon={Activity}
						iconColor="text-blue-600"
						trend={{ value: comparison.changes.total_sessions }}
					/>
					<StatCard
						title="Avg Session Duration"
						value={`${summary.avg_session_duration_min.toFixed(1)} min`}
						icon={Clock}
						iconColor="text-purple-600"
						trend={{ value: comparison.changes.avg_session_duration_min }}
					/>
					<StatCard
						title="Avg Response Time"
						value={`${summary.avg_response_time_sec.toFixed(1)}s`}
						icon={Timer}
						iconColor="text-green-600"
						trend={{ value: comparison.changes.avg_response_time_sec }}
					/>
				</div>
			)}

			{/* Dimension Analysis */}
			<AnalyticsCard className="mb-8">
				<h3 className="text-lg font-semibold mb-4">
					Multi-Dimensional Analysis
				</h3>
				<p className="text-sm text-muted mb-6">
					Analyze sessions across different dimensions and metrics.
				</p>

				<div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
					<div>
						<label
							htmlFor="sessions-metric-select"
							className="block text-sm font-medium text-subheading mb-2"
						>
							Measure (Y-Axis)
						</label>
						<Select
							value={selectedMetric}
							onValueChange={(v) =>
								setSelectedMetric(v as DimensionAnalysisInput["metric"])
							}
						>
							<SelectTrigger className="w-full">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="session_count">Session Count</SelectItem>
								<SelectItem value="avg_duration">Avg Duration (min)</SelectItem>
								<SelectItem value="total_duration">
									Total Duration (hours)
								</SelectItem>
								<SelectItem value="avg_tokens">Avg Tokens</SelectItem>
								<SelectItem value="total_tokens">Total Tokens</SelectItem>
								<SelectItem value="avg_success_score">
									Avg Success Score
								</SelectItem>
								<SelectItem value="total_errors">Total Errors</SelectItem>
							</SelectContent>
						</Select>
					</div>
					<div>
						<label
							htmlFor="sessions-dimension-select"
							className="block text-sm font-medium text-subheading mb-2"
						>
							Group By (X-Axis)
						</label>
						<Select
							value={selectedDimension}
							onValueChange={(v) =>
								setSelectedDimension(v as DimensionAnalysisInput["dimension"])
							}
						>
							<SelectTrigger className="w-full">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="session_archetype">Session Type</SelectItem>
								<SelectItem value="model_used">Model Used</SelectItem>
								<SelectItem value="user_id">User/Developer</SelectItem>
								<SelectItem value="project_path">Project</SelectItem>
								<SelectItem value="repository">Repository</SelectItem>
								<SelectItem value="has_commit">Has Commit</SelectItem>
							</SelectContent>
						</Select>
					</div>
					<div>
						<label
							htmlFor="sessions-splitby-select"
							className="block text-sm font-medium text-subheading mb-2"
						>
							Split By (Optional)
						</label>
						<Select
							value={selectedSplitBy || "none"}
							onValueChange={(v) => {
								const value = v === "none" ? "" : v;
								setSelectedSplitBy(
									value as DimensionAnalysisInput["dimension"] | "",
								);
								if (!value) setShowPercentage(false);
							}}
						>
							<SelectTrigger className="w-full">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="none">None</SelectItem>
								<SelectItem value="session_archetype">Session Type</SelectItem>
								<SelectItem value="model_used">Model Used</SelectItem>
								<SelectItem value="user_id">User/Developer</SelectItem>
								<SelectItem value="repository">Repository</SelectItem>
							</SelectContent>
						</Select>
					</div>
				</div>

				{selectedSplitBy && (
					<div className="mb-4 flex justify-end items-center gap-3">
						<span className="text-sm text-muted">
							{showPercentage ? "Showing as %" : "Showing absolute values"}
						</span>
						<Switch
							checked={showPercentage}
							onCheckedChange={setShowPercentage}
						/>
					</div>
				)}

				{dimensionLoading ? (
					<div className="flex items-center justify-center h-64">
						<div className="text-center">
							<Spinner className="mb-2" />
							<p className="text-muted">Loading chart...</p>
						</div>
					</div>
				) : (
					<DimensionAnalysisChart
						data={dimensionData || []}
						dimension={selectedDimension}
						metric={selectedMetric}
						split_by={selectedSplitBy || undefined}
						showPercentage={showPercentage}
						userMap={userMap}
					/>
				)}
			</AnalyticsCard>

			{/* Sessions Table */}
			<AnalyticsCard>
				<div className="flex items-center justify-between mb-4">
					<div>
						<h3 className="text-lg font-semibold">
							Recent Sessions ({filteredSessions.length})
						</h3>
					</div>
					<div className="flex gap-3">
						<MultiSelect
							options={repositories}
							selected={selectedRepositories}
							onChange={setSelectedRepositories}
							placeholder="All Repositories"
							className="w-48"
						/>
						<MultiSelect
							options={users}
							selected={selectedUsers}
							onChange={setSelectedUsers}
							placeholder="All Developers"
							className="w-48"
						/>
					</div>
				</div>

				<DataTable
					columns={columns}
					data={filteredSessions}
					defaultSorting={[{ id: "date", desc: true }]}
					onRowClick={(row) =>
						navigate(`/dashboard/sessions/${row.session_id}`)
					}
				/>
			</AnalyticsCard>
		</div>
	);
}

import type { ProjectInvestment } from "@rudel/api-routes";
import { useQuery } from "@tanstack/react-query";
import type { ColumnDef } from "@tanstack/react-table";
import {
	Clock,
	DollarSign,
	FolderKanban,
	TrendingUp,
	Users,
	Zap,
} from "lucide-react";
import { useMemo } from "react";
import { useNavigate } from "react-router-dom";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { ProjectTrendChart } from "@/components/charts/ProjectTrendChart";
import { DataTable } from "@/components/ui/data-table";
import { useDateRange } from "@/contexts/DateRangeContext";
import { encodeProjectPath } from "@/lib/format";
import { orpc } from "@/lib/orpc";

function formatTokens(tokens: number) {
	if (tokens >= 1_000_000) return `${(tokens / 1_000_000).toFixed(1)}M`;
	if (tokens >= 1_000) return `${(tokens / 1_000).toFixed(1)}K`;
	return tokens.toString();
}

const columns: ColumnDef<ProjectInvestment>[] = [
	{
		accessorKey: "project_path",
		header: "Project",
		cell: ({ row }) => {
			const remote = row.original.git_remote;
			const name = remote
				? remote.split("/").pop()
				: row.original.project_path.split("/").pop();
			return <span className="font-medium text-foreground">{name}</span>;
		},
	},
	{
		accessorKey: "sessions",
		header: "Sessions",
		cell: ({ row }) => (
			<span className="text-muted">{row.original.sessions}</span>
		),
	},
	{
		accessorFn: (row) => row.total_duration_min,
		id: "time",
		header: "Time",
		cell: ({ row }) => (
			<span className="text-muted">
				{(row.original.total_duration_min / 60).toFixed(1)}h
			</span>
		),
	},
	{
		accessorKey: "total_tokens",
		header: "Tokens",
		cell: ({ row }) => (
			<span className="text-muted">
				{formatTokens(row.original.total_tokens || 0)}
			</span>
		),
	},
	{
		accessorKey: "success_rate",
		header: "Success Rate",
		cell: ({ row }) => {
			const rate = row.original.success_rate || 0;
			const color =
				rate >= 70
					? "text-status-success-icon"
					: rate >= 50
						? "text-status-warning-icon"
						: "text-status-error-icon";
			return (
				<span className={`font-semibold ${color}`}>{rate.toFixed(0)}%</span>
			);
		},
	},
	{
		accessorKey: "cost",
		header: "Cost",
		cell: ({ row }) => (
			<span className="text-muted">${(row.original.cost || 0).toFixed(2)}</span>
		),
	},
	{
		accessorKey: "success_rate_trend",
		header: "Trend",
		cell: ({ row }) => {
			const trend = row.original.success_rate_trend || 0;
			const icon = trend > 0 ? "\u2191" : trend < 0 ? "\u2193" : "-";
			const color =
				trend > 0
					? "text-status-success-icon"
					: trend < 0
						? "text-status-error-icon"
						: "text-muted";
			return (
				<span className={`font-semibold ${color}`}>
					{icon} {Math.abs(trend).toFixed(1)}%
				</span>
			);
		},
	},
];

export function ProjectsListPage() {
	const navigate = useNavigate();
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const { data: projects, isLoading } = useQuery(
		orpc.analytics.projects.investment.queryOptions({ input: { days } }),
	);

	const { data: trendData } = useQuery(
		orpc.analytics.projects.trends.queryOptions({ input: { days } }),
	);

	const sortedProjects = useMemo(() => projects ?? [], [projects]);

	const totalProjects = projects?.length ?? 0;
	const totalSessions = projects?.reduce((sum, p) => sum + p.sessions, 0) ?? 0;
	const totalHours =
		(projects?.reduce((sum, p) => sum + p.total_duration_min, 0) ?? 0) / 60;
	const totalCost = projects?.reduce((sum, p) => sum + (p.cost || 0), 0) ?? 0;
	const totalTokens =
		projects?.reduce((sum, p) => sum + (p.total_tokens || 0), 0) ?? 0;
	const avgUsersPerProject =
		totalProjects > 0
			? (
					(projects?.reduce((sum, p) => sum + p.unique_users, 0) ?? 0) /
					totalProjects
				).toFixed(1)
			: "0";

	const handleRowClick = (row: ProjectInvestment) => {
		const encodedPath = encodeProjectPath(row.project_path);
		navigate(`/dashboard/projects/${encodedPath}`);
	};

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Projects"
					description="Analyze project activity and team investment"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading project metrics...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Projects"
				description="Analyze project activity and team investment"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-6 gap-6 mb-8">
				<StatCard
					title="Active Projects"
					value={totalProjects}
					icon={FolderKanban}
					iconColor="text-blue-600"
				/>
				<StatCard
					title="Total Sessions"
					value={totalSessions.toLocaleString()}
					icon={TrendingUp}
					iconColor="text-green-600"
				/>
				<StatCard
					title="Total Time"
					value={totalHours.toFixed(0)}
					icon={Clock}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Total Tokens"
					value={formatTokens(totalTokens)}
					icon={Zap}
					iconColor="text-amber-600"
				/>
				<StatCard
					title="Total Cost"
					value={`$${totalCost.toFixed(2)}`}
					icon={DollarSign}
					iconColor="text-emerald-600"
				/>
				<StatCard
					title="Avg Users"
					value={avgUsersPerProject}
					icon={Users}
					iconColor="text-indigo-600"
				/>
			</div>

			{trendData && trendData.length > 0 && (
				<AnalyticsCard className="mb-8">
					<h2 className="text-xl font-bold text-heading mb-4">
						Project Trends
					</h2>
					<p className="text-sm text-muted mb-6">
						Activity metrics over time split by project (top 10)
					</p>
					<ProjectTrendChart data={trendData} maxProjects={10} />
				</AnalyticsCard>
			)}

			<AnalyticsCard>
				<h2 className="text-xl font-bold text-heading mb-4">Project Details</h2>
				<DataTable
					columns={columns}
					data={sortedProjects}
					defaultSorting={[{ id: "sessions", desc: true }]}
					onRowClick={handleRowClick}
				/>
			</AnalyticsCard>
		</div>
	);
}

import type { DeveloperError, DeveloperSession } from "@rudel/api-routes";
import { useQuery } from "@tanstack/react-query";
import type { ColumnDef } from "@tanstack/react-table";
import { Activity, ArrowLeft, Calendar, Clock, Code, Zap } from "lucide-react";
import { useMemo, useState } from "react";
import { Link, useParams } from "react-router-dom";
import {
	Bar,
	BarChart,
	CartesianGrid,
	Legend,
	Line,
	LineChart,
	ResponsiveContainer,
	Tooltip,
	XAxis,
	YAxis,
} from "recharts";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { Button } from "@/components/ui/button";
import { DataTable } from "@/components/ui/data-table";
import {
	Select,
	SelectContent,
	SelectItem,
	SelectTrigger,
	SelectValue,
} from "@/components/ui/select";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useChartTheme } from "@/hooks/useChartTheme";
import {
	calculateRollingAverage,
	calculateWeekOverWeek,
	formatWoWChange,
	getTrendColor,
	getTrendDirection,
	getTrendIcon,
} from "@/lib/analytics";
import { formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

export function DeveloperDetailPage() {
	const { userId } = useParams<{ userId: string }>();
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const chartTheme = useChartTheme();
	const days = calculateDays();

	const [projectFilter, setProjectFilter] = useState<string>("");
	const [outcomeFilter, setOutcomeFilter] = useState<"all" | "success">("all");

	const { data: details, isLoading: detailsLoading } = useQuery(
		orpc.analytics.developers.details.queryOptions({
			input: { userId: userId as string, days },
		}),
	);

	const { data: sessions } = useQuery(
		orpc.analytics.developers.sessions.queryOptions({
			input: {
				userId: userId as string,
				days,
				limit: 100,
				projectPath: projectFilter || undefined,
				outcome: outcomeFilter,
				sortBy: "date" as const,
				sortOrder: "desc" as const,
			},
		}),
	);

	const { data: projects } = useQuery(
		orpc.analytics.developers.projects.queryOptions({
			input: { userId: userId as string, days },
		}),
	);

	const { data: timeline } = useQuery(
		orpc.analytics.developers.timeline.queryOptions({
			input: { userId: userId as string, days },
		}),
	);

	const { data: features } = useQuery(
		orpc.analytics.developers.features.queryOptions({
			input: { userId: userId as string, days },
		}),
	);

	const { data: errors } = useQuery(
		orpc.analytics.developers.errors.queryOptions({
			input: { userId: userId as string, days },
		}),
	);

	const { data: userMappings } = useQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
	);

	const userMapRecord = useMemo(() => {
		const record: Record<string, string> = {};
		if (userMappings) {
			for (const m of userMappings) {
				record[m.user_id] = m.username;
			}
		}
		return record;
	}, [userMappings]);

	const username = formatUsername(userId || "", userMapRecord);

	const chartData = useMemo(() => {
		if (!timeline) return [];
		const sessionValues = timeline.map((d) => d.sessions);
		const rollingAvg7 = calculateRollingAverage(sessionValues, 7);
		const rollingAvg30 = calculateRollingAverage(sessionValues, 30);

		return timeline.map((day, index) => ({
			date: new Date(day.date).toLocaleDateString("en-US", {
				month: "short",
				day: "numeric",
			}),
			sessions: day.sessions,
			hours: parseFloat((day.total_duration_min / 60).toFixed(1)),
			avg7Sessions: rollingAvg7[index],
			avg30Sessions: rollingAvg30[index],
		}));
	}, [timeline]);

	const { wowChange, trendColorClass, trendIcon } = useMemo(() => {
		if (!timeline || timeline.length < 14) {
			return {
				wowChange: 0,
				trendColorClass: "text-gray-500",
				trendIcon: "\u2192",
			};
		}
		const sessionValues = timeline.map((d) => d.sessions);
		const currentWeek = sessionValues.slice(-7);
		const previousWeek = sessionValues.slice(-14, -7);
		const wow = calculateWeekOverWeek(currentWeek, previousWeek);
		const direction = getTrendDirection(sessionValues);
		return {
			wowChange: wow,
			trendColorClass: getTrendColor(direction),
			trendIcon: getTrendIcon(direction),
		};
	}, [timeline]);

	const projectChartData = useMemo(() => {
		if (!projects) return [];
		return projects.slice(0, 10).map((p) => ({
			name: p.project_path.split("/").pop() || "Unknown",
			sessions: p.sessions,
			hours: parseFloat((p.total_duration_min / 60).toFixed(1)),
		}));
	}, [projects]);

	const uniqueProjects = useMemo(() => {
		if (!sessions) return [];
		return Array.from(new Set(sessions.map((s) => s.project_path)));
	}, [sessions]);

	const errorColumns = useMemo<ColumnDef<DeveloperError>[]>(
		() => [
			{
				accessorKey: "error_pattern",
				header: "Error Type",
				cell: ({ row }) => (
					<span className="font-medium text-foreground">
						{row.original.error_pattern}
					</span>
				),
			},
			{
				accessorKey: "occurrences",
				header: "Occurrences",
				cell: ({ row }) => (
					<span className="text-muted">{row.original.occurrences}</span>
				),
			},
			{
				accessorFn: (row) => new Date(row.last_seen).getTime(),
				id: "last_seen",
				header: "Last Seen",
				cell: ({ row }) => (
					<span className="text-muted">
						{new Date(row.original.last_seen).toLocaleDateString()}
					</span>
				),
			},
		],
		[],
	);

	const sessionColumns = useMemo<ColumnDef<DeveloperSession>[]>(
		() => [
			{
				accessorFn: (row) => new Date(row.session_date).getTime(),
				id: "date",
				header: "Date",
				cell: ({ row }) => (
					<span className="text-muted">
						{new Date(row.original.session_date).toLocaleString()}
					</span>
				),
			},
			{
				accessorKey: "project_path",
				header: "Project",
				cell: ({ row }) => (
					<span className="font-medium text-foreground">
						{row.original.project_path.split("/").pop()}
					</span>
				),
			},
			{
				accessorKey: "duration_min",
				header: "Duration",
				cell: ({ row }) => (
					<span className="text-muted">
						{row.original.duration_min.toFixed(0)}m
					</span>
				),
			},
			{
				accessorKey: "total_tokens",
				header: "Tokens",
				cell: ({ row }) => (
					<span className="text-muted">
						{(row.original.total_tokens / 1000).toFixed(0)}K
					</span>
				),
			},
			{
				id: "features",
				header: "Features",
				enableSorting: false,
				cell: ({ row }) => (
					<div className="flex gap-1">
						{row.original.has_subagents && (
							<span className="px-2 py-1 text-xs bg-blue-100 text-blue-800 rounded">
								SA
							</span>
						)}
						{row.original.has_skills && (
							<span className="px-2 py-1 text-xs bg-purple-100 text-purple-800 rounded">
								SK
							</span>
						)}
						{row.original.has_slash_commands && (
							<span className="px-2 py-1 text-xs bg-green-100 text-green-800 rounded">
								SC
							</span>
						)}
					</div>
				),
			},
			{
				id: "status",
				header: "Status",
				enableSorting: false,
				cell: ({ row }) => {
					if (row.original.likely_success) {
						return (
							<span className="px-2 py-1 text-xs bg-status-success-bg text-status-success-text rounded-full">
								Success
							</span>
						);
					}
					if (row.original.has_errors) {
						return (
							<span className="px-2 py-1 text-xs bg-status-error-bg text-status-error-text rounded-full">
								Error
							</span>
						);
					}
					return (
						<span className="px-2 py-1 text-xs bg-surface text-subheading rounded-full">
							Unknown
						</span>
					);
				},
			},
		],
		[],
	);

	if (detailsLoading || !details) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Developer Details"
					description="Loading developer information..."
					actions={
						<Button variant="outline" size="sm" asChild>
							<Link to="/dashboard/developers">
								<ArrowLeft className="h-4 w-4" />
								Back to Developers
							</Link>
						</Button>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title={username}
				description="Detailed developer activity and metrics"
				actions={
					<div className="flex items-center gap-3">
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
						<Button variant="outline" size="sm" asChild>
							<Link to="/dashboard/developers">
								<ArrowLeft className="h-4 w-4" />
								Back
							</Link>
						</Button>
					</div>
				}
			/>

			{/* Summary Stats */}
			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
				<StatCard
					title="Total Sessions"
					value={details.total_sessions}
					icon={Activity}
					iconColor="text-blue-600"
				/>
				<StatCard
					title="Active Days"
					value={details.active_days}
					icon={Calendar}
					iconColor="text-green-600"
				/>
				<StatCard
					title="Total Tokens"
					value={`${(details.total_tokens / 1000000).toFixed(1)}M`}
					icon={Code}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Avg Session"
					value={`${details.avg_session_duration_min.toFixed(0)}m`}
					icon={Clock}
					iconColor="text-orange-600"
				/>
			</div>

			{/* Activity Timeline */}
			{chartData.length > 0 && (
				<AnalyticsCard className="mb-8">
					<div className="flex justify-between items-start mb-4">
						<div>
							<h2 className="text-xl font-bold text-heading">
								Daily Activity{" "}
								<span className={`ml-2 ${trendColorClass}`}>{trendIcon}</span>
							</h2>
						</div>
						{timeline && timeline.length >= 14 && (
							<div className="bg-surface px-4 py-2 rounded-lg">
								<p className="text-xs text-muted">Week-over-Week</p>
								<p
									className={`text-lg font-bold ${wowChange >= 0 ? "text-status-success-icon" : "text-status-error-icon"}`}
								>
									{formatWoWChange(wowChange)}
								</p>
							</div>
						)}
					</div>
					<ResponsiveContainer width="100%" height={300}>
						<LineChart data={chartData}>
							<CartesianGrid
								strokeDasharray="3 3"
								stroke={chartTheme.gridStroke}
							/>
							<XAxis dataKey="date" stroke={chartTheme.axisStroke} />
							<YAxis yAxisId="left" stroke={chartTheme.axisStroke} />
							<YAxis
								yAxisId="right"
								orientation="right"
								stroke={chartTheme.axisStroke}
							/>
							<Tooltip
								contentStyle={{
									backgroundColor: chartTheme.tooltipBg,
									borderColor: chartTheme.tooltipBorder,
								}}
							/>
							<Legend />
							<Line
								yAxisId="left"
								type="monotone"
								dataKey="sessions"
								stroke="#3b82f6"
								strokeWidth={2}
								name="Sessions"
							/>
							<Line
								yAxisId="right"
								type="monotone"
								dataKey="hours"
								stroke="#10b981"
								strokeWidth={2}
								name="Hours"
							/>
							<Line
								yAxisId="left"
								type="monotone"
								dataKey="avg7Sessions"
								stroke="#93c5fd"
								strokeWidth={2}
								strokeDasharray="5 5"
								name="7-Day Avg"
								dot={false}
							/>
							<Line
								yAxisId="left"
								type="monotone"
								dataKey="avg30Sessions"
								stroke="#fb923c"
								strokeWidth={2}
								strokeDasharray="5 5"
								name="30-Day Avg"
								dot={false}
							/>
						</LineChart>
					</ResponsiveContainer>
				</AnalyticsCard>
			)}

			{/* Feature Adoption */}
			{features && (
				<div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
					<AnalyticsCard>
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm text-muted">Subagents</p>
								<p className="text-2xl font-bold text-heading">
									{features.subagents_adoption_rate.toFixed(0)}%
								</p>
							</div>
							<Zap className="h-8 w-8 text-blue-600" />
						</div>
					</AnalyticsCard>
					<AnalyticsCard>
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm text-muted">Skills</p>
								<p className="text-2xl font-bold text-heading">
									{features.skills_adoption_rate.toFixed(0)}%
								</p>
							</div>
							<Zap className="h-8 w-8 text-purple-600" />
						</div>
					</AnalyticsCard>
					<AnalyticsCard>
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm text-muted">Slash Commands</p>
								<p className="text-2xl font-bold text-heading">
									{features.slash_commands_adoption_rate.toFixed(0)}%
								</p>
							</div>
							<Zap className="h-8 w-8 text-green-600" />
						</div>
					</AnalyticsCard>
				</div>
			)}

			{/* Projects */}
			{projectChartData.length > 0 && (
				<AnalyticsCard className="mb-8">
					<h2 className="text-xl font-bold text-heading mb-6">
						Projects Worked On
					</h2>
					<ResponsiveContainer width="100%" height={350}>
						<BarChart data={projectChartData} margin={{ bottom: 60 }}>
							<CartesianGrid
								strokeDasharray="3 3"
								stroke={chartTheme.gridStroke}
							/>
							<XAxis
								dataKey="name"
								angle={-45}
								textAnchor="end"
								height={80}
								interval={0}
								stroke={chartTheme.axisStroke}
							/>
							<YAxis yAxisId="left" stroke={chartTheme.axisStroke} />
							<YAxis
								yAxisId="right"
								orientation="right"
								stroke={chartTheme.axisStroke}
							/>
							<Tooltip
								contentStyle={{
									backgroundColor: chartTheme.tooltipBg,
									borderColor: chartTheme.tooltipBorder,
								}}
							/>
							<Legend />
							<Bar
								yAxisId="left"
								dataKey="sessions"
								fill="#3b82f6"
								name="Sessions"
							/>
							<Bar
								yAxisId="right"
								dataKey="hours"
								fill="#10b981"
								name="Hours"
							/>
						</BarChart>
					</ResponsiveContainer>
				</AnalyticsCard>
			)}

			{/* Errors */}
			{errors && errors.length > 0 && (
				<AnalyticsCard className="mb-8">
					<h2 className="text-xl font-bold text-heading mb-4">
						Errors Encountered
					</h2>
					<DataTable
						columns={errorColumns}
						data={errors}
						defaultSorting={[{ id: "occurrences", desc: true }]}
						defaultPageSize={50}
					/>
				</AnalyticsCard>
			)}

			{/* Session History */}
			<AnalyticsCard>
				<div className="flex justify-between items-center mb-4">
					<h2 className="text-xl font-bold text-heading">Session History</h2>
					<div className="flex gap-3">
						<Select
							value={projectFilter || "all"}
							onValueChange={(v) => setProjectFilter(v === "all" ? "" : v)}
						>
							<SelectTrigger className="w-auto">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="all">All Projects</SelectItem>
								{uniqueProjects.map((path) => (
									<SelectItem key={path} value={path}>
										{path.split("/").pop()}
									</SelectItem>
								))}
							</SelectContent>
						</Select>
						<Select
							value={outcomeFilter}
							onValueChange={(v) => setOutcomeFilter(v as "all" | "success")}
						>
							<SelectTrigger className="w-auto">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="all">All Outcomes</SelectItem>
								<SelectItem value="success">Likely Success</SelectItem>
							</SelectContent>
						</Select>
					</div>
				</div>

				<DataTable
					columns={sessionColumns}
					data={sessions ?? []}
					defaultSorting={[{ id: "date", desc: true }]}
				/>
			</AnalyticsCard>
		</div>
	);
}

import type { ProjectContributor, ProjectError } from "@rudel/api-routes";
import { useQuery } from "@tanstack/react-query";
import type { ColumnDef } from "@tanstack/react-table";
import { Activity, ArrowLeft, Clock, Code, Users, Zap } from "lucide-react";
import { useMemo } from "react";
import { Link, useParams } from "react-router-dom";
