import type {
	DeveloperCostBreakdown,
	ProjectCostBreakdown,
} from "@rudel/api-routes";
import { useQuery } from "@tanstack/react-query";
import type { ColumnDef } from "@tanstack/react-table";
import {
	Activity,
	DollarSign,
	Target,
	TrendingDown,
	TrendingUp,
} from "lucide-react";
import { useMemo, useState } from "react";
import {
	CartesianGrid,
	Line,
	LineChart,
	ResponsiveContainer,
	Tooltip,
	XAxis,
	YAxis,
} from "recharts";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { Button } from "@/components/ui/button";
import { DataTable } from "@/components/ui/data-table";
import { Input } from "@/components/ui/input";
import { Spinner } from "@/components/ui/spinner";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useChartTheme } from "@/hooks/useChartTheme";
import { formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

export function ROIPage() {
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const chartTheme = useChartTheme();
	const days = calculateDays();

	const [roiInputs, setRoiInputs] = useState({
		codePercentage: 65,
		tokensPerLOC: 15,
		locPerHour: 30,
		devHourlyRate: 100,
	});

	const { data: metrics, isLoading } = useQuery(
		orpc.analytics.roi.metrics.queryOptions({ input: { days } }),
	);

	const { data: trends } = useQuery(
		orpc.analytics.roi.trends.queryOptions({ input: { days: 56 } }),
	);

	const { data: developerCosts } = useQuery(
		orpc.analytics.roi.breakdownDevelopers.queryOptions({ input: { days } }),
	);

	const { data: projectCosts } = useQuery(
		orpc.analytics.roi.breakdownProjects.queryOptions({ input: { days } }),
	);

	const { data: userMappings } = useQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 90 } }),
	);

	const userMapRecord = useMemo(() => {
		const record: Record<string, string> = {};
		if (userMappings) {
			for (const m of userMappings) {
				record[m.user_id] = m.username;
			}
		}
		return record;
	}, [userMappings]);

	const devCostColumns = useMemo<ColumnDef<DeveloperCostBreakdown>[]>(
		() => [
			{
				accessorFn: (row) => formatUsername(row.user_id, userMapRecord),
				id: "developer",
				header: "Developer",
				cell: ({ row }) => (
					<span className="font-medium text-foreground">
						{formatUsername(row.original.user_id, userMapRecord)}
					</span>
				),
			},
			{
				accessorKey: "cost",
				header: "Cost",
				cell: ({ row }) => (
					<span className="text-right text-subheading">
						${row.original.cost.toFixed(2)}
					</span>
				),
			},
			{
				accessorKey: "sessions",
				header: "Sessions",
				cell: ({ row }) => (
					<span className="text-right text-subheading">
						{row.original.sessions}
					</span>
				),
			},
		],
		[userMapRecord],
	);

	const projectCostColumns = useMemo<ColumnDef<ProjectCostBreakdown>[]>(
		() => [
			{
				accessorKey: "project_path",
				header: "Project",
				cell: ({ row }) => (
					<span className="font-medium text-foreground truncate max-w-xs">
						{row.original.project_path.split("/").pop() ||
							row.original.project_path}
					</span>
				),
			},
			{
				accessorKey: "cost",
				header: "Cost",
				cell: ({ row }) => (
					<span className="text-right text-subheading">
						${row.original.cost.toFixed(2)}
					</span>
				),
			},
			{
				accessorKey: "sessions",
				header: "Sessions",
				cell: ({ row }) => (
					<span className="text-right text-subheading">
						{row.original.sessions}
					</span>
				),
			},
		],
		[],
	);

	const formatCurrency = (value: number) => `$${value.toFixed(2)}`;
	const formatPercent = (value: number) =>
		`${value >= 0 ? "+" : ""}${value.toFixed(1)}%`;

	const formatCompact = (value: number): string => {
		if (value >= 1_000_000) return `${(value / 1_000_000).toFixed(1)}M`;
		if (value >= 1_000) return `${(value / 1_000).toFixed(1)}K`;
		return value.toString();
	};

	const calculatedROI = useMemo(() => {
		if (!metrics) return null;
		const loc =
			(metrics.output_tokens * (roiInputs.codePercentage / 100)) /
			roiInputs.tokensPerLOC;
		const hoursSaved = loc / roiInputs.locPerHour;
		const valueCreated = hoursSaved * roiInputs.devHourlyRate;
		const dollarValueSaved = valueCreated - metrics.total_cost;
		const roiPercentage =
			metrics.total_cost > 0
				? (dollarValueSaved / metrics.total_cost) * 100
				: 0;

		return {
			loc: Math.round(loc),
			hoursSaved: parseFloat(hoursSaved.toFixed(2)),
			valueCreated: parseFloat(valueCreated.toFixed(2)),
			dollarValueSaved: parseFloat(dollarValueSaved.toFixed(2)),
			roiPercentage: parseFloat(roiPercentage.toFixed(2)),
		};
	}, [metrics, roiInputs]);

	const resetToDefaults = () => {
		setRoiInputs({
			codePercentage: 65,
			tokensPerLOC: 15,
			locPerHour: 30,
			devHourlyRate: 100,
		});
	};

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="ROI & Business Value"
				description="Track return on investment and measure business impact of Claude Code"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{isLoading && (
				<div className="flex items-center justify-center py-12">
					<div className="text-center">
						<Spinner size="lg" className="mb-4" />
						<p className="text-muted">Loading ROI data...</p>
					</div>
				</div>
			)}

			{!isLoading && metrics && calculatedROI && (
				<>
					{/* Input Configuration */}
					<AnalyticsCard className="mb-6">
						<div className="mb-4">
							<h3 className="text-lg font-semibold text-heading">
								ROI Calculation Parameters
							</h3>
							<p className="text-sm text-muted mt-1">
								Adjust inputs to explore different ROI scenarios
							</p>
						</div>
						<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
							<div>
								<label
									htmlFor="codePercentage"
									className="block text-sm font-medium text-subheading mb-1"
								>
									Code Percentage (%)
								</label>
								<Input
									id="codePercentage"
									type="number"
									value={roiInputs.codePercentage}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											codePercentage: parseFloat(e.target.value) || 0,
										})
									}
									min={0}
									max={100}
								/>
								<p className="text-xs text-muted mt-1">
									% of output that is actual code
								</p>
							</div>
							<div>
								<label
									htmlFor="tokensPerLOC"
									className="block text-sm font-medium text-subheading mb-1"
								>
									Tokens per LOC
								</label>
								<Input
									id="tokensPerLOC"
									type="number"
									value={roiInputs.tokensPerLOC}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											tokensPerLOC: parseFloat(e.target.value) || 1,
										})
									}
									min={1}
								/>
								<p className="text-xs text-muted mt-1">
									Average tokens per line of code
								</p>
							</div>
							<div>
								<label
									htmlFor="locPerHour"
									className="block text-sm font-medium text-subheading mb-1"
								>
									LOC per Hour (baseline)
								</label>
								<Input
									id="locPerHour"
									type="number"
									value={roiInputs.locPerHour}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											locPerHour: parseFloat(e.target.value) || 1,
										})
									}
									min={1}
								/>
								<p className="text-xs text-muted mt-1">
									Manual coding speed without Claude
								</p>
							</div>
							<div>
								<label
									htmlFor="devHourlyRate"
									className="block text-sm font-medium text-subheading mb-1"
								>
									Developer Rate ($/hr)
								</label>
								<Input
									id="devHourlyRate"
									type="number"
									value={roiInputs.devHourlyRate}
									onChange={(e) =>
										setRoiInputs({
											...roiInputs,
											devHourlyRate: parseFloat(e.target.value) || 1,
										})
									}
									min={1}
								/>
								<p className="text-xs text-muted mt-1">Hourly developer cost</p>
							</div>
						</div>
						<div className="mt-4">
							<Button variant="outline" size="sm" onClick={resetToDefaults}>
								Reset to Defaults
							</Button>
						</div>
					</AnalyticsCard>

					{/* KPI Cards */}
					<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
						<StatCard
							title="Total Spend"
							value={formatCurrency(metrics.total_cost)}
							icon={DollarSign}
							iconColor="text-red-600"
							trend={{ value: metrics.total_cost_change_pct }}
						/>
						<StatCard
							title="Cost per Commit"
							value={
								metrics.cost_per_commit > 0
									? formatCurrency(metrics.cost_per_commit)
									: "N/A"
							}
							icon={Target}
							iconColor="text-blue-600"
							trend={{ value: metrics.cost_per_commit_change_pct }}
						/>
						<StatCard
							title="Dev Hours Saved"
							value={`${formatCompact(calculatedROI.hoursSaved)}h`}
							icon={Activity}
							iconColor="text-green-600"
							trend={{ value: metrics.dev_hours_saved_change_pct }}
						/>
						<StatCard
							title="Dollar Value Saved"
							value={`$${formatCompact(calculatedROI.dollarValueSaved)}`}
							icon={
								calculatedROI.roiPercentage >= 0 ? TrendingUp : TrendingDown
							}
							iconColor={
								calculatedROI.roiPercentage >= 0
									? "text-green-600"
									: "text-red-600"
							}
						/>
					</div>

					{/* ROI Breakdown */}
					<AnalyticsCard className="mb-8">
						<div className="mb-4">
							<h3 className="text-lg font-semibold text-heading">
								ROI Calculation Breakdown
							</h3>
						</div>
						<div className="bg-surface rounded-lg p-6 font-mono text-sm">
							<div className="space-y-2">
								<div className="flex justify-between">
									<span className="text-muted">Output Tokens:</span>
									<span className="font-semibold text-foreground">
										{formatCompact(metrics.output_tokens)}
									</span>
								</div>
								<div className="flex justify-between">
									<span className="text-muted">
										Code % ({roiInputs.codePercentage}%):
									</span>
									<span className="font-semibold text-foreground">
										{formatCompact(calculatedROI.loc)} LOC
									</span>
								</div>
								<div className="flex justify-between border-b border-border pb-2">
									<span className="text-muted">
										Hours Saved (LOC / {roiInputs.locPerHour}):
									</span>
									<span className="font-semibold text-foreground">
										{formatCompact(calculatedROI.hoursSaved)} hours
									</span>
								</div>
								<div className="pt-2 space-y-2">
									<div className="flex justify-between">
										<span className="text-muted">Value Created:</span>
										<span className="font-semibold text-status-success-icon">
											${formatCompact(calculatedROI.valueCreated)}
										</span>
									</div>
									<div className="flex justify-between">
										<span className="text-muted">Token Cost:</span>
										<span className="font-semibold text-status-error-icon">
											-{formatCurrency(metrics.total_cost)}
										</span>
									</div>
									<div className="flex justify-between border-t-2 border-border pt-2 mt-2">
										<span className="text-foreground font-bold">
											Net Value:
										</span>
										<span className="font-bold text-accent text-lg">
											${formatCompact(calculatedROI.dollarValueSaved)}
										</span>
									</div>
									<div className="flex justify-between">
										<span className="text-foreground font-bold">ROI:</span>
										<span
											className={`font-bold text-lg ${
												calculatedROI.roiPercentage >= 0
													? "text-status-success-icon"
													: "text-status-error-icon"
											}`}
										>
											{formatPercent(calculatedROI.roiPercentage)}
										</span>
									</div>
								</div>
							</div>
						</div>
					</AnalyticsCard>

					{/* Trends Charts */}
					{trends && trends.length > 0 && (
						<div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
							<AnalyticsCard>
								<div className="mb-4">
									<h3 className="text-lg font-semibold text-heading">
										Weekly Cost Trend
									</h3>
									<p className="text-sm text-muted mt-1">
										Total spend over time
									</p>
								</div>
								<ResponsiveContainer width="100%" height={300}>
									<LineChart data={trends}>
										<CartesianGrid
											strokeDasharray="3 3"
											stroke={chartTheme.gridStroke}
										/>
										<XAxis
											dataKey="week_start"
											stroke={chartTheme.axisStroke}
											fontSize={12}
											tickFormatter={(value) =>
												new Date(value).toLocaleDateString("en-US", {
													month: "short",
													day: "numeric",
												})
											}
										/>
										<YAxis
											stroke={chartTheme.axisStroke}
											fontSize={12}
											tickFormatter={(value) => `$${value}`}
										/>
										<Tooltip
											contentStyle={{
												backgroundColor: chartTheme.tooltipBg,
												borderColor: chartTheme.tooltipBorder,
											}}
											formatter={(value) => [
												`$${((value as number) ?? 0).toFixed(2)}`,
												"Cost",
											]}
											labelFormatter={(label) =>
												`Week of ${new Date(label).toLocaleDateString()}`
											}
										/>
										<Line
											type="monotone"
											dataKey="total_cost"
											stroke="#3b82f6"
											strokeWidth={2}
											dot={{ r: 4 }}
										/>
									</LineChart>
								</ResponsiveContainer>
							</AnalyticsCard>

							<AnalyticsCard>
								<div className="mb-4">
									<h3 className="text-lg font-semibold text-heading">
										Weekly Productivity Score
									</h3>
									<p className="text-sm text-muted mt-1">
										Commits per dollar x 100
									</p>
								</div>
								<ResponsiveContainer width="100%" height={300}>
									<LineChart data={trends}>
										<CartesianGrid
											strokeDasharray="3 3"
											stroke={chartTheme.gridStroke}
										/>
										<XAxis
											dataKey="week_start"
											stroke={chartTheme.axisStroke}
											fontSize={12}
											tickFormatter={(value) =>
												new Date(value).toLocaleDateString("en-US", {
													month: "short",
													day: "numeric",
												})
											}
										/>
										<YAxis stroke={chartTheme.axisStroke} fontSize={12} />
										<Tooltip
											contentStyle={{
												backgroundColor: chartTheme.tooltipBg,
												borderColor: chartTheme.tooltipBorder,
											}}
											labelFormatter={(label) =>
												`Week of ${new Date(label).toLocaleDateString()}`
											}
										/>
										<Line
											type="monotone"
											dataKey="productivity_score"
											stroke="#10b981"
											strokeWidth={2}
											dot={{ r: 4 }}
											name="Productivity Score"
										/>
									</LineChart>
								</ResponsiveContainer>
							</AnalyticsCard>
						</div>
					)}

					{/* Cost Breakdown Tables */}
					<div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
						<AnalyticsCard>
							<h3 className="text-lg font-semibold text-heading mb-4">
								Developer Cost Breakdown
							</h3>
							<DataTable
								columns={devCostColumns}
								data={developerCosts ?? []}
								defaultSorting={[{ id: "cost", desc: true }]}
								defaultPageSize={50}
							/>
						</AnalyticsCard>

						<AnalyticsCard>
							<h3 className="text-lg font-semibold text-heading mb-4">
								Project Cost Breakdown
							</h3>
							<DataTable
								columns={projectCostColumns}
								data={projectCosts ?? []}
								defaultSorting={[{ id: "cost", desc: true }]}
								defaultPageSize={50}
							/>
						</AnalyticsCard>
					</div>
				</>
			)}
		</div>
	);
}

import { useQuery } from "@tanstack/react-query";
import { AlertCircle, AlertTriangle, Clock, Users } from "lucide-react";
import { useMemo, useState } from "react";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { ErrorTrendChart } from "@/components/charts/ErrorTrendChart";
import { useDateRange } from "@/contexts/DateRangeContext";
import { orpc } from "@/lib/orpc";

const severityColors = {
	high: "bg-status-error-bg text-status-error-text border-status-error-border",
	medium:
		"bg-status-warning-bg text-status-warning-text border-status-warning-border",
	low: "bg-status-info-bg text-status-info-text border-status-info-border",
};

const severityIcons = {
	high: "\u{1F534}",
	medium: "\u{1F7E1}",
	low: "\u{1F535}",
};

export function ErrorsPage() {
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const [trendMetric, setTrendMetric] = useState<
		"avg_errors_per_interaction" | "avg_errors_per_session" | "total_errors"
	>("total_errors");
	const [trendSplitBy, setTrendSplitBy] = useState<
		"repository" | "user_id" | "model"
	>("repository");

	const { data: errors, isLoading } = useQuery(
		orpc.analytics.errors.topRecurring.queryOptions({
			input: { days, minOccurrences: 2, limit: 15 },
		}),
	);

	const { data: trendData, isLoading: trendLoading } = useQuery(
		orpc.analytics.errors.trends.queryOptions({
			input: { startDate, endDate, splitBy: trendSplitBy },
		}),
	);

	const { data: userMappings } = useQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
	);

	const userMap = useMemo(() => {
		const map = new Map<string, string>();
		if (userMappings) {
			for (const m of userMappings) {
				map.set(m.user_id, m.username);
			}
		}
		return map;
	}, [userMappings]);

	const totalErrors = errors?.reduce((sum, e) => sum + e.occurrences, 0) ?? 0;
	const highSeverityCount =
		errors?.filter((e) => e.severity === "high").length ?? 0;
	const affectedUsersTotal =
		errors && errors.length > 0
			? Math.max(...errors.map((e) => e.affected_users))
			: 0;
	const mostCommonError =
		errors && errors.length > 0 ? errors[0].error_pattern : "None";

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Error Intelligence"
					description="Track and analyze recurring errors across your team"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading error data...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Error Intelligence"
				description="Track and analyze recurring errors across your team"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{/* Summary Stats */}
			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
				<StatCard
					title="Total Errors"
					value={totalErrors.toLocaleString()}
					subtitle="error occurrences"
					icon={AlertCircle}
					iconColor="text-red-600"
				/>
				<StatCard
					title="High Severity"
					value={highSeverityCount}
					subtitle="critical issues"
					icon={AlertTriangle}
					iconColor="text-orange-600"
				/>
				<StatCard
					title="Most Common"
					value={mostCommonError}
					subtitle="top error type"
					icon={Clock}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Max Affected Users"
					value={affectedUsersTotal}
					subtitle="developers impacted"
					icon={Users}
					iconColor="text-blue-600"
				/>
			</div>

			{/* Error Trends Chart */}
			<AnalyticsCard className="mb-8">
				<h2 className="text-xl font-bold text-heading mb-2">
					Error Trends Over Time
				</h2>
				<p className="text-sm text-muted mb-6">
					Track error metrics across different dimensions to identify patterns
					and trends
				</p>
				{trendLoading ? (
					<div className="text-center py-12 text-muted">
						Loading error trends...
					</div>
				) : (
					<ErrorTrendChart
						data={trendData || []}
						metric={trendMetric}
						splitBy={trendSplitBy}
						onMetricChange={setTrendMetric}
						onSplitByChange={setTrendSplitBy}
						userMap={userMap}
					/>
				)}
			</AnalyticsCard>

			{/* Top Recurring Errors */}
			<AnalyticsCard className="mb-8">
				<h2 className="text-xl font-bold text-heading mb-4">
					Top Recurring Errors
				</h2>
				<p className="text-sm text-muted mb-6">
					Most frequently occurring errors that may need attention
				</p>
				{errors && errors.length > 0 ? (
					<div className="space-y-4">
						{errors.map((err, index) => (
							<div
								// biome-ignore lint/suspicious/noArrayIndexKey: static list of errors
								key={index}
								className="border border-border rounded-lg p-4 hover:shadow-md transition-shadow"
							>
								<div className="flex items-start justify-between">
									<div className="flex-1">
										<div className="flex items-center gap-3 mb-2">
											<span className="text-2xl">
												{
													severityIcons[
														err.severity as keyof typeof severityIcons
													]
												}
											</span>
											<h3 className="text-lg font-semibold text-heading">
												{err.error_pattern}
											</h3>
											<span
												className={`px-3 py-1 rounded-full text-xs font-medium border ${
													severityColors[
														err.severity as keyof typeof severityColors
													]
												}`}
											>
												{err.severity.toUpperCase()}
											</span>
										</div>
										<div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-3">
											<div>
												<p className="text-xs text-muted uppercase">
													Occurrences
												</p>
												<p className="text-lg font-semibold text-foreground">
													{err.occurrences}
												</p>
											</div>
											<div>
												<p className="text-xs text-muted uppercase">
													Affected Users
												</p>
												<p className="text-lg font-semibold text-foreground">
													{err.affected_users}
												</p>
											</div>
											<div>
												<p className="text-xs text-muted uppercase">
													Last Seen
												</p>
												<p className="text-sm text-subheading">
													{new Date(err.last_seen).toLocaleDateString()}
												</p>
											</div>
										</div>
									</div>
								</div>
							</div>
						))}
					</div>
				) : (
					<div className="text-center py-12">
						<div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-status-success-bg mb-4">
							<svg
								className="w-8 h-8 text-status-success-icon"
								fill="none"
								stroke="currentColor"
								viewBox="0 0 24 24"
								role="img"
								aria-label="No errors"
							>
								<path
									strokeLinecap="round"
									strokeLinejoin="round"
									strokeWidth={2}
									d="M5 13l4 4L19 7"
								/>
							</svg>
						</div>
						<p className="text-lg font-medium text-foreground mb-1">
							No recurring errors found!
						</p>
						<p className="text-sm text-muted">
							Great job! Your team hasn't encountered any recurring errors in
							the selected time period.
						</p>
					</div>
				)}
			</AnalyticsCard>

			{/* Error Insights */}
			{errors && errors.length > 0 && (
				<div className="grid grid-cols-1 md:grid-cols-2 gap-6">
					<AnalyticsCard className="bg-status-error-bg border-status-error-border">
						<div className="flex items-start gap-4">
							<div className="p-3 rounded-lg bg-status-error-bg">
								<AlertTriangle className="h-6 w-6 text-status-error-icon" />
							</div>
							<div className="flex-1">
								<h3 className="text-lg font-semibold text-heading mb-2">
									Action Recommended
								</h3>
								<p className="text-sm text-subheading mb-3">
									You have {highSeverityCount} high-severity error
									{highSeverityCount !== 1 ? "s" : ""} that may require
									immediate attention.
								</p>
								{highSeverityCount > 0 && (
									<p className="text-xs text-muted">
										Consider scheduling a team discussion to address these
										issues.
									</p>
								)}
							</div>
						</div>
					</AnalyticsCard>

					<AnalyticsCard className="bg-status-info-bg border-status-info-border">
						<div className="flex items-start gap-4">
							<div className="p-3 rounded-lg bg-status-info-bg">
								<Users className="h-6 w-6 text-accent" />
							</div>
							<div className="flex-1">
								<h3 className="text-lg font-semibold text-heading mb-2">
									Knowledge Sharing
								</h3>
								<p className="text-sm text-subheading mb-3">
									{errors.filter((e) => e.affected_users > 1).length} error type
									{errors.filter((e) => e.affected_users > 1).length !== 1
										? "s"
										: ""}{" "}
									affecting multiple developers.
								</p>
								<p className="text-xs text-muted">
									Share solutions in team channels to help everyone learn.
								</p>
							</div>
						</div>
					</AnalyticsCard>
				</div>
			)}
		</div>
	);
}

import { useQuery } from "@tanstack/react-query";
import { BookOpen, FolderKanban, Lightbulb, Users } from "lucide-react";
import { useMemo, useState } from "react";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { MultiSelect } from "@/components/analytics/MultiSelect";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { LearningsTrendChart } from "@/components/charts/LearningsTrendChart";
import { LearningsTimeline } from "@/components/learnings/LearningsTimeline";
import { useDateRange } from "@/contexts/DateRangeContext";
import { orpc } from "@/lib/orpc";

export function LearningsPage() {
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const [splitBy, setSplitBy] = useState<"user_id" | "repository">("user_id");
	const [selectedUsers, setSelectedUsers] = useState<string[]>([]);
	const [selectedProjects, setSelectedProjects] = useState<string[]>([]);

	const { data: learnings, isLoading } = useQuery(
		orpc.analytics.learnings.list.queryOptions({
			input: { days, limit: 100, offset: 0 },
		}),
	);

	const { data: stats } = useQuery(
		orpc.analytics.learnings.stats.queryOptions({ input: { days } }),
	);

	const { data: trendData } = useQuery(
		orpc.analytics.learnings.trend.queryOptions({
			input: { days, splitBy },
		}),
	);

	const { data: availableUsers } = useQuery(
		orpc.analytics.learnings.users.queryOptions({}),
	);

	const { data: availableProjects } = useQuery(
		orpc.analytics.learnings.projects.queryOptions({}),
	);

	const { data: userMappings } = useQuery(
		orpc.analytics.users.mappings.queryOptions({ input: { days: 30 } }),
	);

	const userMap = useMemo(() => {
		const map = new Map<string, string>();
		if (userMappings) {
			for (const m of userMappings) {
				map.set(m.user_id, m.username);
			}
		}
		return map;
	}, [userMappings]);

	const userDisplayOptions = useMemo(() => {
		if (!availableUsers) return [];
		return availableUsers.map(
			(userId) => userMap.get(userId) || `${userId.substring(0, 8)}...`,
		);
	}, [availableUsers, userMap]);

	const projectDisplayOptions = useMemo(() => {
		if (!availableProjects) return [];
		return availableProjects.map((path) => {
			const name = path.split("/").pop() || path;
			return name;
		});
	}, [availableProjects]);

	const filteredLearnings = useMemo(() => {
		if (!learnings) return [];
		return learnings.filter((learning) => {
			if (
				selectedUsers.length > 0 &&
				!selectedUsers.includes(learning.user_id)
			) {
				return false;
			}
			if (
				selectedProjects.length > 0 &&
				!selectedProjects.includes(learning.project_path)
			) {
				return false;
			}
			return true;
		});
	}, [learnings, selectedUsers, selectedProjects]);

	const handleUserFilterChange = (selectedNames: string[]) => {
		if (!availableUsers) return;
		const userIds = selectedNames.map((name) => {
			const userId = availableUsers.find(
				(id) => (userMap.get(id) || `${id.substring(0, 8)}...`) === name,
			);
			return userId || name;
		});
		setSelectedUsers(userIds);
	};

	const handleProjectFilterChange = (selected: string[]) => {
		if (!availableProjects) return;
		const fullPaths = selected.map((name) => {
			const path = availableProjects.find((p) => p.split("/").pop() === name);
			return path || name;
		});
		setSelectedProjects(fullPaths);
	};

	const hasData = !isLoading && stats != null && stats.total_learnings > 0;

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Learning Feed"
				description="Team feedback and insights from /compound:feedback sessions"
				actions={
					hasData ? (
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					) : undefined
				}
			/>

			{!isLoading && !hasData && (
				<AnalyticsCard className="mt-4">
					<div className="flex flex-col items-center justify-center py-20 px-4 text-center">
						<div className="w-16 h-16 rounded-full bg-muted flex items-center justify-center mb-6">
							<Lightbulb className="w-8 h-8 text-muted-foreground" />
						</div>
						<h3 className="text-lg font-semibold text-foreground mb-3">
							No learnings yet
						</h3>
						<p className="text-sm text-muted-foreground max-w-lg mb-6">
							This feature is powered by our internal continuous improvement
							system at{" "}
							<a
								href="https://obsessiondb.com"
								target="_blank"
								rel="noopener noreferrer"
								className="text-foreground underline underline-offset-2 hover:text-foreground/80"
							>
								ObsessionDB
							</a>
							. We are working on open-sourcing this workflow so you can set up
							your own continuous improvement agent system for your team.
						</p>
						<p className="text-xs text-muted-foreground/60 max-w-md">
							Stay tuned — once available, learnings will automatically appear
							here as your team captures feedback during coding sessions.
						</p>
					</div>
				</AnalyticsCard>
			)}

			{hasData && (
				<>
					{/* Stats Overview */}
					{stats && (
						<div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
							<StatCard
								title="Total Learnings"
								value={stats.total_learnings.toString()}
								icon={BookOpen}
								subtitle={`${stats.learnings_by_day.length} days with feedback`}
							/>
							<StatCard
								title="Team Members"
								value={stats.unique_users.toString()}
								icon={Users}
								subtitle="Contributing feedback"
							/>
							<StatCard
								title="Projects"
								value={stats.unique_projects.toString()}
								icon={FolderKanban}
								subtitle="With learnings captured"
							/>
						</div>
					)}

					{/* Filters */}
					<div className="mb-6 flex flex-wrap gap-4">
						<MultiSelect
							options={userDisplayOptions}
							selected={selectedUsers.map(
								(userId) =>
									userMap.get(userId) || `${userId.substring(0, 8)}...`,
							)}
							onChange={handleUserFilterChange}
							placeholder="All Users"
							className="w-64"
						/>
						<MultiSelect
							options={projectDisplayOptions}
							selected={selectedProjects.map((path) => {
								const name = path.split("/").pop() || path;
								return name;
							})}
							onChange={handleProjectFilterChange}
							placeholder="All Projects"
							className="w-64"
						/>
						{(selectedUsers.length > 0 || selectedProjects.length > 0) && (
							<button
								type="button"
								onClick={() => {
									setSelectedUsers([]);
									setSelectedProjects([]);
								}}
								className="px-4 py-2 text-sm text-muted hover:text-foreground hover:bg-hover rounded-md transition-colors"
							>
								Clear filters
							</button>
						)}
					</div>

					{/* Learnings Trend Chart */}
					{trendData && trendData.length > 0 && (
						<AnalyticsCard className="mb-6">
							<h2 className="text-xl font-bold text-heading mb-4">
								Learnings Over Time
							</h2>
							<p className="text-sm text-muted mb-6">
								Feedback activity over time split by developer
							</p>
							<LearningsTrendChart
								data={trendData}
								splitBy={splitBy}
								onSplitByChange={setSplitBy}
								userMap={userMap}
							/>
						</AnalyticsCard>
					)}

					{/* Timeline */}
					<AnalyticsCard>
						<div className="p-6">
							{filteredLearnings.length > 0 && (
								<div className="flex items-center justify-end mb-6">
									<span className="text-sm text-muted">
										{filteredLearnings.length}{" "}
										{filteredLearnings.length === 1 ? "learning" : "learnings"}
									</span>
								</div>
							)}

							<LearningsTimeline
								learnings={filteredLearnings}
								isLoading={isLoading}
								userMap={Object.fromEntries(userMap)}
							/>
						</div>
					</AnalyticsCard>
				</>
			)}
		</div>
	);
}

import { useQuery } from "@tanstack/react-query";
import { useParams } from "react-router-dom";
import { ConversationList } from "@/components/sessions/conversation/ConversationList";
import { SessionHeader } from "@/components/sessions/SessionHeader";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { useSession } from "@/hooks/useSession";
import { orpc } from "@/lib/orpc";

export function SessionDetailPage() {
	const { sessionId } = useParams<{ sessionId: string }>();

	const { data, isLoading, error } = useQuery(
		orpc.analytics.sessions.detail.queryOptions({
			input: { sessionId: sessionId as string },
		}),
	);

	if (isLoading) {
		return (
			<div className="flex flex-col h-full">
				<div className="border-b p-4 space-y-3">
					<Skeleton className="h-8 w-48" />
					<Skeleton className="h-4 w-64" />
					<Skeleton className="h-6 w-96" />
				</div>
				<div className="flex-1 p-4">
					<div className="space-y-4">
						{["sk-1", "sk-2", "sk-3", "sk-4", "sk-5"].map((id) => (
							<Skeleton key={id} className="h-24" />
						))}
					</div>
				</div>
			</div>
		);
	}

	if (error || !data) {
		return (
			<div className="flex items-center justify-center h-96">
				<Card className="max-w-md w-full">
					<CardHeader>
						<CardTitle className="text-destructive">
							Error Loading Session
						</CardTitle>
					</CardHeader>
					<CardContent>
						<p className="text-sm text-muted-foreground">
							Failed to load session data. The session may not exist.
						</p>
					</CardContent>
				</Card>
			</div>
		);
	}

	return <SessionDetailContent session={data} />;
}

interface SessionDetailContentProps {
	session: {
		session_id: string;
		user_id: string;
		session_date: string;
		project_path: string;
		repository: string | null;
		content: string;
		subagents: Record<string, string>;
		skills: Array<string>;
		slash_commands: Array<string>;
		git_branch: string | null;
		git_sha: string | null;
		total_tokens: number;
		input_tokens: number;
		output_tokens: number;
		success_score?: number;
		duration_min?: number;
		total_interactions?: number;
		session_archetype?: string;
		model_used?: string;
	};
}

function SessionDetailContent({ session }: SessionDetailContentProps) {
	const { conversations, getToolResult, subagents } = useSession(session);

	return (
		<div className="flex flex-col h-full">
			<SessionHeader session={session} />
			<div className="flex-1 overflow-auto p-4">
				<ConversationList
					conversations={conversations}
					getToolResult={getToolResult}
					subagents={subagents}
				/>
			</div>
		</div>
	);
}

