@@ -0,0 +1,16 @@
+import {
+	type UseQueryOptions,
+	type UseQueryResult,
+	useQuery,
+} from "@tanstack/react-query";
+import { useOrganization } from "@/contexts/OrganizationContext";
+
+export function useAnalyticsQuery<TData>(
+	options: UseQueryOptions<TData>,
+): UseQueryResult<TData> {
+	const { activeOrg } = useOrganization();
+	return useQuery({
+		...options,
+		queryKey: ["org", activeOrg?.id, ...(options.queryKey ?? [])],
+	});
+}
diff --git a/apps/web/src/hooks/useFullOrganization.ts b/apps/web/src/hooks/useFullOrganization.ts
new file mode 100644
index 0000000..927908f
--- /dev/null
+++ b/apps/web/src/hooks/useFullOrganization.ts
@@ -0,0 +1,43 @@
+import { useQuery, useQueryClient } from "@tanstack/react-query";
+import { useCallback } from "react";
+import { authClient } from "@/lib/auth-client";
+
+interface FullOrg {
+	id: string;
+	name: string;
+	slug: string;
+	members: readonly {
+		id: string;
+		userId: string;
+		role: string;
+		user: { id: string; name: string; email: string; image: string | null };
+	}[];
+	invitations: readonly {
+		id: string;
+		email: string;
+		role: string | null;
+		status: string;
+	}[];
+}
+
+export function useFullOrganization(orgId: string | undefined) {
+	const queryClient = useQueryClient();
+	const queryKey = ["full-organization", orgId] as const;
+
+	const { data, isLoading } = useQuery({
+		queryKey,
+		queryFn: async () => {
+			const res = await authClient.organization.getFullOrganization({
+				query: { organizationId: orgId as string },
+			});
+			return (res.data as unknown as FullOrg) ?? null;
+		},
+		enabled: !!orgId,
+	});
+
+	const invalidate = useCallback(() => {
+		queryClient.invalidateQueries({ queryKey });
+	}, [queryClient, queryKey]);
+
+	return { data: data ?? null, isLoading, invalidate };
+}
